import Heading from './components/Heading';

const projects = [
  { title: "Project One", description: "A short line about what this is.", year: "2025" },
  { title: "Project Two", description: "Another thing you made or worked on.", year: "2024" },
  { title: "Project Three", description: "Keep these descriptions tight.", year: "2024" },
];

function App() {

  return (
    <div className="page">

      <main>
      <Heading />
      <section>
        <h3 className="roundedBorder">Featured Work!</h3>
      </section>
      </main>

    </div>
  );

}

export default App;
